import React, { useEffect, useState } from 'react';
import { analyticsService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function Analytics() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [kpis, setKpis] = useState(null);
  const [metrics, setMetrics] = useState(null);
  const [timeRange, setTimeRange] = useState('7d');

  useEffect(() => {
    loadData();
  }, [timeRange]);

  const loadData = async () => {
    setLoading(true);
    setError('');
    try {
      const [kpiData, metricsData] = await Promise.all([
        analyticsService.getKpiSummary(),
        analyticsService.getPerformanceMetrics(timeRange)
      ]);
      setKpis(kpiData);
      setMetrics(metricsData);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-header">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <h1 className="page-title">📊 Analytics Dashboard</h1>
          <p className="page-subtitle">Real-time operational insights and performance metrics</p>
        </div>
        <select className="select-field" value={timeRange} onChange={(e) => setTimeRange(e.target.value)}>
          <option value="7d">Last 7 Days</option>
          <option value="30d">Last 30 Days</option>
          <option value="90d">Last 90 Days</option>
        </select>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : error ? (
          <div style={{ color: '#ff4444', padding: '20px', background: 'rgba(255, 68, 68, 0.1)', borderRadius: '8px' }}>
            {error}
          </div>
        ) : (
          <>
            {/* KPI Summary */}
            <div className="grid grid-4">
              {kpis && Object.entries(kpis).map(([key, value]) => (
                <div key={key} className="card interactive">
                  <div className="card-header">
                    <div>
                      <div className="card-subtitle">{key.toUpperCase()}</div>
                      <div style={{ fontSize: '32px', fontWeight: '700', marginTop: '8px' }}>
                        {value.current}
                      </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div className="badge badge-success">{value.change}%</div>
                    </div>
                  </div>
                  <div style={{ fontSize: '12px', color: '#a0b0c0' }}>
                    vs previous period
                  </div>
                </div>
              ))}
            </div>

            {/* Charts Section */}
            <div style={{ marginTop: '32px' }}>
              <div className="grid grid-2">
                <div className="card">
                  <div className="card-header">
                    <div>
                      <div className="card-title">Collection Efficiency</div>
                      <div className="card-subtitle">Route optimization & time metrics</div>
                    </div>
                  </div>
                  <div style={{ padding: '20px', textAlign: 'center', height: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <div style={{ fontSize: '14px', color: '#a0b0c0' }}>
                      📈 Chart visualization will render here
                    </div>
                  </div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <div>
                      <div className="card-title">Incident Trend</div>
                      <div className="card-subtitle">Open, resolved, and pending incidents</div>
                    </div>
                  </div>
                  <div style={{ padding: '20px', textAlign: 'center', height: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <div style={{ fontSize: '14px', color: '#a0b0c0' }}>
                      📉 Chart visualization will render here
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Performance Metrics Table */}
            <div style={{ marginTop: '32px' }}>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">Performance Metrics</div>
                </div>
                <div className="table-container">
                  <table className="table">
                    <thead>
                      <tr>
                        <th>Metric</th>
                        <th>Current</th>
                        <th>Target</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {metrics && metrics.map((metric, idx) => (
                        <tr key={idx} className={metric.status === 'critical' ? 'critical' : ''}>
                          <td>{metric.name}</td>
                          <td style={{ fontWeight: '600' }}>{metric.current}</td>
                          <td>{metric.target}</td>
                          <td>
                            <span className={`badge badge-${metric.status}`}>
                              ● {metric.status.toUpperCase()}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default Analytics;
